import threading
c = threading.Condition()
for op in (lambda: c.notify(), lambda: c.wait(0)):
    try:
        op(); raise SystemExit('FAIL: expected RuntimeError (lock not held)')
    except RuntimeError as e:
        assert 'un-acquired' in str(e) or 'cannot' in str(e)
# FIFO oracle: waiters woken oldest-first.
c2 = threading.Condition(); got = []
def waiter(tag):
    with c2:
        c2.wait(); got.append(tag)
ts = [threading.Thread(target=waiter, args=(i,)) for i in range(3)]
for t in ts: t.start(); __import__('time').sleep(0.02)
for _ in range(3):
    with c2: c2.notify(1)
    __import__('time').sleep(0.02)
for t in ts: t.join(1)
assert got == [0,1,2], ('FIFO violated', got)
